import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"TLDR AI — 2026-05-21","description":"","frontmatter":{"title":"TLDR AI — 2026-05-21","date":"2026-05-21T00:00:00.000Z","source":"TLDR AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-21-tldr-ai.md","filePath":"research/ai-news/2026-05/2026-05-21-tldr-ai.md","lastUpdated":1779894392000}'),o={name:"research/ai-news/2026-05/2026-05-21-tldr-ai.md"};function i(s,e,l,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="⚡-tldr-ai-—-2026-05-21" tabindex="-1">⚡ TLDR AI — 2026-05-21 <a class="header-anchor" href="#⚡-tldr-ai-—-2026-05-21" aria-label="Permalink to &quot;⚡ TLDR AI — 2026-05-21&quot;">​</a></h1><blockquote><p>5 分鐘科技簡報，AI + 程式 + 產品精華濃縮 來源：<a href="https://tldr.tech/api/rss/ai" target="_blank" rel="noreferrer">TLDR AI</a></p></blockquote><hr><h2 id="gemini-3-5-flash-⚡️-karpathy-joins-anthropic-🧑‍💻-openai-guaranteed-capacity-⚡" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-20" target="_blank" rel="noreferrer">Gemini 3.5 Flash ⚡️, Karpathy joins Anthropic 🧑‍💻, OpenAI Guaranteed Capacity ⚡</a> <a class="header-anchor" href="#gemini-3-5-flash-⚡️-karpathy-joins-anthropic-🧑‍💻-openai-guaranteed-capacity-⚡" aria-label="Permalink to &quot;[Gemini 3.5 Flash ⚡️, Karpathy joins Anthropic 🧑‍💻, OpenAI Guaranteed Capacity ⚡](https://tldr.tech/ai/2026-05-20)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-20</em></p><p><strong><a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/gemini-3-5/?utm_source=tldrai" target="_blank" rel="noreferrer">Gemini 3.5 Flash (5 minute read)</a></strong> Google has introduced Gemini 3.5 Flash, a new model focused on agentic workflows, coding, and long-horizon task execution. The release also expanded Gemini access across Search, enterprise tools, Android Studio, and Google&#39;s developer platforms. <strong><a href="https://x.com/karpathy/status/2056753169888334312?utm_source=tldrai" target="_blank" rel="noreferrer">Karpathy joins Anthropic (1 minute read)</a></strong> Andrej Karpathy announced he has joined Anthropic, citing the next few years at the LLM frontier as especially formative for his return to R&amp;D. Karpathy noted he remains passionate about education and plans to resume that work later, signaling the move is research-focused rather than a permanent pivot away from teaching. <strong><a href="https://www.cnbc.com/2026/05/19/openai-announces-new-guaranteed-capacity-offering-for-customers-to-secure-compute.html?utm_source=tldrai" target="_blank" rel="noreferrer">OpenAI announces new Guaranteed Capacity offering for customers to secure compute (3 minute read)</a></strong> OpenAI&#39;s new Guaranteed Capacity offering allows customers to secure long-term access to compute to power AI products, agents, and workflows. Customers can choose between one-, two-, and three-year-long commitments, with discounts based on how long the commitment is. The company will offer Guaranteed Capacity until it sells out of its current allocation. It plans to offer it again in the future. <strong><a href="https://blog.google/innovation-and-ai/sundar-pichai-io-2026/?utm_source=tldrai" target="_blank" rel="noreferrer">Google Detailed the Shift Toward Agentic Gemini Products (19 minute read)</a></strong> At I/O 2026, Google outlined how Gemini models were being integrated across consumer products, creative tools, and developer platforms. The company also shared that monthly token usage across its AI systems had grown to more than 3.2 quadrillion. <strong><a href="https://aifoc.us/model-half-life/?utm_source=tldrai" target="_blank" rel="noreferrer">Model half-life (4 minute read)</a></strong> Model half-life - the idea that model releases will keep getting faster and faster - doesn&#39;t really make sense under consideration. Model releases have definitely increased in pace, but the release time isn&#39;t halving every six months. This post looks at model release dates for several of the most well-known models and lays out predictions for when the next models might come out. <strong><a href="https://claude.com/blog/using-claude-code-the-unreasonable-effectiveness-of-html?utm_source=tldrai" target="_blank" rel="noreferrer">Using Claude Code: The unreasonable effectiveness of HTML (10 minute read)</a></strong> HTML&#39;s richness allows it to convey complex information more effectively than Markdown, including layouts, data tables, and interactive elements. It enhances readability by organizing specs into well-structured, easily navigable documents and offers better sharing and interaction capabilities. Claude Code uses HTML to efficiently ingest context from various sources, aiding in specs, design prototyping, and creating custom editing interfaces with improved engagement and clarity. <strong><a href="https://github.com/NVlabs/LongLive?utm_source=tldrai" target="_blank" rel="noreferrer">Real-Time Long Video Generation (GitHub Repo)</a></strong> NVIDIA&#39;s LongLive 1.0 is a framework for interactive long-form video generation that supports sequential prompting and real-time user-guided editing using streaming attention and KV-cache optimization techniques. <strong><a href="https://huggingface.co/blog/allenai/olmoearth-v1-1?utm_source=tldrai" target="_blank" rel="noreferrer">OlmoEarth v1.1: A more efficient family of models (5 minute read)</a></strong> OlmoEarth v1.1, a new model family, reduces compute costs by up to 3X while maintaining performance, making planet-scale mapping more affordable. The models efficiently process remote sensing data by optimizing token sequence lengths, crucial for reducing computational costs. Methodological improvements allow similar performance to the original version with significantly less compute, benefiting developers and enhancing scientific research in remote sensing. <strong><a href="https://www.warp.dev/blog/multi-harness-cloud-agent-orchestration?utm_source=tldrai" target="_blank" rel="noreferrer">A single pane of glass for managing all of your cloud agents (5 minute read)</a></strong> Oz is a multi-harness control plane for cloud agents, supporting Claude Code, Codex, and Warp Agent. It offers automatic multi-agent orchestration, cross-harness Agent Memory, and improved cost and usage controls. Additionally, Oz provides expanded self-hosting options and enhanced governance features, streamlining agent management and deployment. <strong><a href="https://huggingface.co/blog/ettin-reranker?utm_source=tldrai" target="_blank" rel="noreferrer">Introducing the Ettin Reranker Family (19 minute read)</a></strong> Six new state-of-the-art CrossEncoder Ettin rerankers built on Ettin ModernBERT encoders have been released, offering models from 17M to 1B parameters. These models, trained with pointwise MSE distillation from a strong 1.54B parameter teacher, provide significant accuracy improvements over legacy models while enhancing speed, especially with Flash Attention 2. The models are particularly notable for their efficiency in retrieve-then-rerank systems and outperform models like ms-marco-MiniLM-L12-v2 on MTEB and NanoBEIR benchmarks. <strong><a href="https://nanransohoff.substack.com/p/the-third-wave-of-american-philanthropy?utm_source=tldrai" target="_blank" rel="noreferrer">The third wave of American philanthropy (23 minute read)</a></strong> AI is about to generate hundreds of billions in new philanthropic funding. <strong><a href="https://openai.com/index/advancing-content-provenance/?utm_source=tldrai" target="_blank" rel="noreferrer">Advancing content provenance for a safer, more transparent AI ecosystem (6 minute read)</a></strong> OpenAI strengthens content provenance by implementing C2PA standards and Google DeepMind&#39;s SynthID watermarking for AI-generated images. <strong><a href="https://threadreaderapp.com/thread/2056752047031279726.html?utm_source=tldrai" target="_blank" rel="noreferrer">Index (2 minute read)</a></strong> Index is a platform for content owners that helps them understand how AI agents use their work and earn revenue when they do. <strong><a href="https://threadreaderapp.com/thread/2056778123329274279.html?utm_source=tldrai" target="_blank" rel="noreferrer">Cerebras is now running Kimi K2.6 (1 minute read)</a></strong> Kimi K2.6, a trillion-parameter model, has the fastest frontier model performance ever measured by Artificial Analysis at around 1,000 tokens per second. <strong><a href="https://jobs.ashbyhq.com/tldr.tech/3b21aaf8-dea5-4127-be71-602d30e5001e?utm_source=tldrai" target="_blank" rel="noreferrer">TLDR is hiring a Senior Software Engineer, Applied AI ($250k-$350k, Fully Remote)</a></strong> TLDR&#39;s Applied AI team is tasked with making every process at TLDR legible to code, runnable by anyone, and composable into larger workflows. Join a small, fast moving team using the latest AI tools with an unlimited token budget. Learn more .</p><hr><h2 id="qwen-3-7-🤖-cursor-composer-2-5-👨‍💻-anthropic-acquires-stainless-🛠️" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-19" target="_blank" rel="noreferrer">Qwen 3.7 🤖, Cursor Composer 2.5 👨‍💻, Anthropic acquires Stainless 🛠️</a> <a class="header-anchor" href="#qwen-3-7-🤖-cursor-composer-2-5-👨‍💻-anthropic-acquires-stainless-🛠️" aria-label="Permalink to &quot;[Qwen 3.7 🤖, Cursor Composer 2.5 👨‍💻, Anthropic acquires Stainless 🛠️](https://tldr.tech/ai/2026-05-19)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-19</em></p><p><strong><a href="https://threadreaderapp.com/thread/2056403591464984753.html?utm_source=tldrai" target="_blank" rel="noreferrer">Qwen3.7 Preview lands on Arena (1 minute read)</a></strong> Qwen3.7 Preview is now on Arena for Text and Vision. Qwen3.7 Max Preview ranks 13th overall in Text Arena, while Qwen3.7 Plus Preview ranks 16th overall in Vision Arena. <strong><a href="https://cursor.com/blog/composer-2-5?utm_source=tldrai" target="_blank" rel="noreferrer">Cursor Released Composer 2.5 (7 minute read)</a></strong> Cursor introduced Composer 2.5, an updated coding agent trained with targeted reinforcement learning, synthetic data, and new distributed training techniques. <strong><a href="https://www.anthropic.com/news/anthropic-acquires-stainless?utm_source=tldrai" target="_blank" rel="noreferrer">Anthropic Acquires SDK Startup Stainless (4 minute read)</a></strong> Anthropic acquired developer tools startup Stainless, whose SDK automation platform was widely used by AI companies, including OpenAI, Google, and Cloudflare. <strong><a href="https://vas-blog.pages.dev/qwen-censorship/?utm_source=tldrai" target="_blank" rel="noreferrer">What political censorship looks like inside an LLM&#39;s weights (109 minute read)</a></strong> Qwen3.5-9B&#39;s political censorship is a small circuit that can be read and turned off. The factual knowledge is already in pretraining. The censorship behavior is layered on top of the facts. The model never loses the knowledge, it just learns to route around it. <strong><a href="https://cameronrwolfe.substack.com/p/agent-evals?utm_source=tldrai" target="_blank" rel="noreferrer">Agent Evaluation: A Detailed Guide (53 minute read)</a></strong> LLM evaluation has shifted from static benchmarks to more dynamic, real-world agent systems. Effective evaluation now requires realistic harnesses to test agents over long time horizons in complex environments. This is crucial as agents increasingly adopt high-stakes roles, such as coding and medicine, necessitating rigorous performance measurement and outcome-oriented evaluation. <strong><a href="https://huggingface.co/blog/nvidia/cosmos-fine-tuning-for-robot-video-generation?utm_source=tldrai" target="_blank" rel="noreferrer">Fine-Tuning NVIDIA Cosmos Predict 2.5 with LoRA/DoRA for Robot Video Generation (9 minute read)</a></strong> NVIDIA Cosmos Predict 2.5 generates videos from text, adapting for specific tasks like robot manipulation using LoRA/DoRA to inject trainable adapters, minimizing memory use. These methods offer efficient fine-tuning on a single GPU, preventing catastrophic forgetting while generating synthetic trajectories quickly. Fine-tuning with LoRA and DoRA significantly improves video quality, with LoRA more suited for tight memory conditions and DoRA preferred for addressing training instability. <strong><a href="https://github.com/sapientinc/HRM-Text?utm_source=tldrai" target="_blank" rel="noreferrer">HRM-Text (GitHub Repo)</a></strong> HRM-Text is a 1B text generation model based on the HRM architecture. It can be trained with 130-600x less compute and 150-900x less data than foundation models, making foundation model pretraining accessible. The 0.6B parameter version of the model can be trained on 8 H100s on a single node in about 50 hours for around $800. The 1B parameter model can be trained on 16 H100s on two nodes in about 46 hours for around $1,472. <strong><a href="https://jiaxin-wen.github.io/blog/generalization-dynamics?utm_source=tldrai" target="_blank" rel="noreferrer">Generalization Dynamics of LM Pre-training (17 minute read)</a></strong> Language models (LMs) undergo unpredictable switches between parroting patterns and exhibiting adaptive intelligence during pre-training, a phenomenon termed &quot;mode-hopping.&quot; This behavior cannot be corrected by standard optimization techniques and presents as a competition for model capacity, influenced by data from each training window. Researchers propose leveraging these dynamics to better select pre-training checkpoints, curate data for stable generalization, and evaluate metrics predicting LM behavior. <strong><a href="https://blogs.nvidia.com/blog/vera-cpu-delivery/?utm_source=tldrai" target="_blank" rel="noreferrer">Vera Arrives: NVIDIA&#39;s First CPU Built for Agents Lands at Top AI Labs (4 minute read)</a></strong> The first Nvidia Vera CPUs recently arrived at Anthropic, OpenAI, SpaceXAI, and Oracle. They were hand-delivered by Nvidia Vice President of Hyperscale and High-Performance Computing, Ian Buck. Vera features 88 custom Nvidia-designed Olympus cores, 1.2 TB/s of memory bandwidth, and 50% faster per-core performance. It is the host processor for Vera Rubin NVL72, which pairs via second-generation Nvidia NVLink-C2C to a pair of Rubin GPUs. <strong><a href="https://www.npr.org/2026/05/18/nx-s1-5822366/musk-altman-openai-jury-verdict-claims-dismissed?utm_source=tldrai" target="_blank" rel="noreferrer">Jury dismisses all claims in Elon Musk&#39;s lawsuit against OpenAI CEO Sam Altman (6 minute read)</a></strong> Elon Musk&#39;s lawsuit against Sam Altman and OpenAI has been dismissed. A jury has decided that Musk waited too long to file his lawsuit. Musk says he plans to appeal. <strong><a href="https://x.ai/news/grok-skills?utm_source=tldrai" target="_blank" rel="noreferrer">Skills in web, iOS, and Android (2 minute read)</a></strong> xAI launched &quot;Skills&quot; for Grok, allowing users to teach it functions once, which it remembers across interactions. <strong><a href="https://gist.github.com/kanmadigital/2369c4f5ea410cb8f6a1647b40c0e2a1?utm_source=tldrai" target="_blank" rel="noreferrer">LLM Wiki v2 (16 minute read)</a></strong> This post contains a pattern for building personal knowledge bases using LLMs. <strong><a href="https://manus.im/blog/manus-schedules?utm_source=tldrai" target="_blank" rel="noreferrer">Introducing Scheduled Tasks 2.0 (7 minute read)</a></strong> Scheduled Tasks 2.0 enhances automation by allowing tasks to run with context, ensuring continuity in workflows across different projects and apps. <strong><a href="https://lovable.dev/blog/introducing-skills?utm_source=tldrai" target="_blank" rel="noreferrer">Turn repeated instructions into reusable skills in Lovable (14 minute read)</a></strong> Skills in Lovable allow users to create reusable, markdown-based instructions to eliminate repetitive explanations. <strong><a href="https://jobs.ashbyhq.com/tldr.tech/3b21aaf8-dea5-4127-be71-602d30e5001e?utm_source=tldrai" target="_blank" rel="noreferrer">TLDR is hiring a Senior Software Engineer, Applied AI ($250k-$350k, Fully Remote)</a></strong> TLDR&#39;s Applied AI team is tasked with making every process at TLDR legible to code, runnable by anyone, and composable into larger workflows. Join a small, fast moving team using the latest AI tools with an unlimited token budget. Learn more .</p><hr><h2 id="gemini-extended-thinking-✨-chatgpt-finance-📱-claude-code-at-scale-👨‍💻" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-18" target="_blank" rel="noreferrer">Gemini Extended Thinking ✨, ChatGPT finance 📱, Claude Code at scale 👨‍💻</a> <a class="header-anchor" href="#gemini-extended-thinking-✨-chatgpt-finance-📱-claude-code-at-scale-👨‍💻" aria-label="Permalink to &quot;[Gemini Extended Thinking ✨, ChatGPT finance 📱, Claude Code at scale 👨‍💻](https://tldr.tech/ai/2026-05-18)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-18</em></p><p><strong><a href="https://openai.com/index/personal-finance-chatgpt/?utm_source=tldrai" target="_blank" rel="noreferrer">ChatGPT Personal Finance (6 minute read)</a></strong> OpenAI released a preview of a new personal finance experience in ChatGPT for Pro users in the US. The feature lets users securely connect financial accounts, view spending dashboards, and ask questions grounded in their financial context and goals. <strong><a href="https://9to5google.com/2026/05/17/gemini-app-thinking-level/?utm_source=tldrai" target="_blank" rel="noreferrer">Gemini app rolling out ‘Extended&#39; thinking level, new 3rd-party app integrations (3 minute read)</a></strong> Google is rolling out a new &#39;Thinking level&#39; option for Gemini. The option has appeared for some users when they select Fast or Gemini 3.1 Pro. Google is also preparing to add more integrations with third-party apps in Gemini. Support for Canva, Instacart, and OpenTable appears to be coming. <strong><a href="https://www.testingcatalog.com/openai-will-let-codex-control-other-desktop-devices-via-computer-use/?utm_source=tldrai" target="_blank" rel="noreferrer">Codex will soon be able to control other desktop devices via Computer Use (2 minute read)</a></strong> OpenAI is working on a capability that lets its coding agent operate macOS applications through Computer Use even when a laptop is locked or asleep. Computer Use currently requires an unlocked, awake session to see the screen, move the cursor, and type. Lifting the restriction will allow users to direct their agents without having to walk back to their machines to log in first. It is unknown when the feature will be released. <strong><a href="https://x.com/sriramkri/status/2054594308494229882?utm_source=tldrai" target="_blank" rel="noreferrer">AI economics part 2 (11 minute read)</a></strong> AI labs are in an ongoing war over GPU resources. That article looks into demand and supply and how the infrastructure powering AI today may not be sufficient. Scaling GPUs doesn&#39;t scale compute linearly. Efficiency matters more at raw scale given finite supply. <strong><a href="https://x.com/PatrickToulme/status/2055709800986780028?utm_source=tldrai" target="_blank" rel="noreferrer">Portability Is a Myth: Why the Best AI Stacks Will Never Be Hardware-Agnostic (15 minute read)</a></strong> AI kernel portability is structurally impossible because TPU&#39;s Pallas, NVIDIA&#39;s CuTile and CUTLASS, AWS&#39;s NKI, AMD&#39;s FlyDSL, and Tenstorrent&#39;s tt-Metalium each expose hardware-specific concepts that no universal DSL can unify. The evidence: MaxText&#39;s MoE grouped matmul ships as 282 lines of Pallas on TPU while flashinfer&#39;s equivalent for Blackwell SM100 takes 4 million lines of generated CUDA, with zero shared code because the algorithms themselves diverge across hardware. <strong><a href="https://skids.dev/blog/anthropic-cache-tokenomics/?utm_source=tldrai" target="_blank" rel="noreferrer">Tokenomics: the 62.5-minute rule for Claude&#39;s cache (8 minute read)</a></strong> If you expect to need a cache before 62.5 minutes, refresh it. Otherwise, let it expire. This number stays the same between models, and it doesn&#39;t change, no matter the size of the cache. The amount of dollars may change, but the decision point is still the same. <strong><a href="https://claude.com/blog/how-claude-code-works-in-large-codebases-best-practices-and-where-to-start?utm_source=tldrai" target="_blank" rel="noreferrer">How Claude Code works in large codebases: Best practices and where to start (5 minute read)</a></strong> Claude Code is now being used in production across multiple large codebases in organizations with thousands of developers. These environments bring challenges that smaller codebases don&#39;t. This article covers patterns that Anthropic has seen that have led to the successful adoption of Claude Code at scale. It looks at how Claude Code has been used in monorepos with millions of lines, legacy systems built over decades, and microservices across separate repositories. <strong><a href="https://magazine.sebastianraschka.com/p/recent-developments-in-llm-architectures?utm_source=tldrai" target="_blank" rel="noreferrer">Recent Developments in LLM Architectures: KV Sharing, mHC, and Compressed Attention (33 minute read)</a></strong> KV-cache size, memory traffic, and attention cost quickly become the main constraints as reasoning models and agent workflows keep more tokens around for longer. LLM developers are adding a growing number of architecture tricks to reduce costs. Most of the changes look like small tweaks, but some are quite intricate design changes. This article looks at these architecture changes with a focus on what changes inside the transformer block, residual stream, KV cache, and attention computation. <strong><a href="https://nousresearch.com/lighthouse-attention?utm_source=tldrai" target="_blank" rel="noreferrer">Lighthouse Attention (11 minute read)</a></strong> Lighthouse Attention, a selection-based hierarchical attention, offers up to 17x faster forward and backward passes than standard attention models at large contexts. It utilizes FlashAttention on a dense sub-sequence, maintaining efficiency and compatibility with upstream improvements. By enabling efficient long-context training and retaining dense model competence, Lighthouse Attention achieves 1.4x to 1.7x speedup in pretraining while reducing computational costs. <strong><a href="https://www.dwarkesh.com/p/notes-on-pretraining-parallelisms?utm_source=tldrai" target="_blank" rel="noreferrer">Notes on pretraining parallelisms and failed training runs (12 minute read)</a></strong> Pretraining runs often fail. This article looks at all the ways that things can go wrong and why training is such a precarious operation. The key culprits seem to be breaking causality and adding bias. <strong><a href="https://techcrunch.com/2026/05/16/the-haves-and-have-nots-of-the-ai-gold-rush/?utm_source=tldrai" target="_blank" rel="noreferrer">The haves and have nots of the AI gold rush (1 minute read)</a></strong> The AI boom has created a wealth divide, with an estimated 10,000 individuals from companies like OpenAI and Nvidia achieving over $20M in wealth, while others face uncertain futures with stagnant job prospects and layoffs. Software engineers express concerns about their skills becoming obsolete, raising anxiety about career paths. This disparity fuels tension in San Francisco&#39;s tech scene as some criticize the dual role of AI as a wealth source and a career threat. <strong><a href="https://techcrunch.com/2026/05/15/runway-started-by-helping-filmmakers-now-it-wants-to-beat-google-at-ai/?utm_source=tldrai" target="_blank" rel="noreferrer">Runway started by helping filmmakers — now it wants to beat Google at AI (11 minute read)</a></strong> Runway&#39;s founders believe that the next form of AI will be built from video and world models that learn how the world works. The company is training models directly on observational data to reach the next frontier of AI. Runway was one of the first to develop AI video generation, but world models are a different race with deep-pocketed competitors. The company has raised $860 million to date, but it is going against incumbents like OpenAI and Google. <strong><a href="https://github.com/chopratejas/headroom?utm_source=tldrai" target="_blank" rel="noreferrer">Headroom (GitHub Repo)</a></strong> Headroom compresses everything an agent reads before it reaches the LLM to produce the same answers at a fraction of the tokens. <strong><a href="https://www.williamangel.net/blog/2026/05/17/offline-llm-energy-use.html?utm_source=tldrai" target="_blank" rel="noreferrer">Apple Silicon costs more than OpenRouter (3 minute read)</a></strong> Openrouter costs about 1/3 the price at around 2x the speed for comparable models. <strong><a href="https://www.seangoedecke.com/steering-vectors/?utm_source=tldrai" target="_blank" rel="noreferrer">DeepSeek-V4-Flash means LLM steering is interesting again (9 minute read)</a></strong> Steering is the idea that LLM outputs can be guided by directly manipulating the activations of a model mid-flight. <strong><a href="https://www.implicator.ai/openai-quietly-bought-voice-cloning-startup-weights-gg-then-folded-the-team/?utm_source=tldrai" target="_blank" rel="noreferrer">OpenAI Quietly Bought Voice-Cloning Startup Weights.gg, Then Folded the Team (3 minute read)</a></strong> OpenAI acquired the six-person team and its intellectual properties, then shut down Weights.gg and dispersed its team across multiple OpenAI groups. <strong><a href="https://jobs.ashbyhq.com/tldr.tech/3b21aaf8-dea5-4127-be71-602d30e5001e?utm_source=tldrai" target="_blank" rel="noreferrer">TLDR is hiring a Senior Software Engineer, Applied AI ($250k-$350k, Fully Remote)</a></strong> TLDR&#39;s Applied AI team is tasked with making every process at TLDR legible to code, runnable by anyone, and composable into larger workflows. Join a small, fast moving team using the latest AI tools with an unlimited token budget. Learn more .</p><hr><h2 id="grok-build-👨‍💻-codex-customizations-🤖-xai-exodus-👋" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-15" target="_blank" rel="noreferrer">Grok Build 👨‍💻 , Codex customizations 🤖, xAI exodus 👋</a> <a class="header-anchor" href="#grok-build-👨‍💻-codex-customizations-🤖-xai-exodus-👋" aria-label="Permalink to &quot;[Grok Build 👨‍💻 , Codex customizations 🤖, xAI exodus 👋](https://tldr.tech/ai/2026-05-15)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-15</em></p><p><strong><a href="https://x.ai/news/grok-build-cli?utm_source=tldrai" target="_blank" rel="noreferrer">Introducing Grok Build (2 minute read)</a></strong> Grok Build is a coding agent that runs from the terminal. It is now in early beta for SuperGrok Heavy subscribers. AGENTS.md, plugin, hooks, skills, and MCP servers all work out of the box. Grok Build supports subagents for larger tasks, and it also supports deep worktree integrations, so users can launch subagents in their own worktrees. There is a headless mode that allows the easy running of agents inside scripts and automations. <strong><a href="https://cursor.com/blog/cloud-agent-development-environments?utm_source=tldrai" target="_blank" rel="noreferrer">Cloud Agent Development Environments (6 minute read)</a></strong> Cursor detailed a new system for configuring cloud-based development environments tailored to autonomous coding agents. It supports multi-repo, environment configuration as code, automated setup workflows, and governance controls for managing fleets of parallel agents. <strong><a href="https://techcrunch.com/2026/05/14/openai-is-reportedly-preparing-legal-action-against-apple-it-wouldnt-be-the-first-partner-to-feel-burned/?utm_source=tldrai" target="_blank" rel="noreferrer">OpenAI Explores Legal Action Against Apple (1 minute read)</a></strong> Bloomberg reported that OpenAI explored legal options against Apple over dissatisfaction with how deeply ChatGPT was integrated into Apple&#39;s ecosystem and the limited subscriber growth that followed. <strong><a href="https://www.anthropic.com/research/2028-ai-leadership?utm_source=tldrai" target="_blank" rel="noreferrer">2028: Two scenarios for global AI leadership (28 minute read)</a></strong> Anthropic outlines two possible 2028 global AI leadership scenarios: one where the US retains its compute advantage and shapes AI norms, and another where China competes closely due to policy inaction. The US currently leads due to strong export controls and advanced chip technology preventing China from keeping pace. Closing loopholes on compute access and restricting distillation attacks are crucial for maintaining the US lead and ensuring democracies shape AI governance. <strong><a href="https://x.com/larsencc/status/2027225210412470668?utm_source=tldrai" target="_blank" rel="noreferrer">How We Built Secure, Scalable Agent Sandbox Infrastructure (8 minute read)</a></strong> There are two ways to sandbox an agent that can execute code: isolate the tool or isolate the agent. Agents should have nothing worth stealing and nothing worth reserving. Isolating the agent requires an extra network hop on every operation and more services to deploy, but there are no secrets to steal, no state to preserve, and agents can be killed, restarted, and scaled independently. <strong><a href="https://threadreaderapp.com/thread/2055032115964870838.html?utm_source=tldrai" target="_blank" rel="noreferrer">Codex is getting easier to automate and customize around your code (1 minute read)</a></strong> Codex has implemented hooks and programmatic tokens to make it easier to automate and customize code. Hooks can customize the Codex loop with scripts that run at key points in a task. Programmatic access provides scoped credentials for Business and Enterprise teams. A video showing how to create access tokens for Codex automations is available. <strong><a href="https://github.com/raindrop-ai/workshop?utm_source=tldrai" target="_blank" rel="noreferrer">Raindrop Workshop (GitHub Repo)</a></strong> Raindrop Workshop gives Claude Code the ability to read traces, write evals against codebases, and fix what&#39;s broken. It provides livestreamed traces, coding-agent integration, a self-healing eval loop, and local replay. Raindrop Workshop is compatible with TypeScript, Python, Go, and Rust, and most popular SDKs, providers, and coding agents. <strong><a href="https://developers.googleblog.com/announcing-genkit-middleware-intercept-extend-and-harden-your-agentic-apps/?utm_source=tldrai" target="_blank" rel="noreferrer">Genkit Middleware (10 minute read)</a></strong> Genkit is a framework for building full-stack, AI-powered and agentic applications for any platform. It supports TypeScript, Go, Dart, and Python. Genkit uses composable hooks that intercept generation calls to implement retries and fall-backs for maximum reliability, human approval before destructive tool calls, and observability across every layer. Its middleware system runs a tool loop that repeats until the model is done. The Genkit Developer can be used to inspect, test, and debug applications and middleware execution. <strong><a href="https://huggingface.co/blog/continuous_async?utm_source=tldrai" target="_blank" rel="noreferrer">Unlocking asynchronicity in continuous batching (20 minute read)</a></strong> Asynchronous batching can reduce idle time between CPU and GPU cycles, improving GPU utilization for inference by 22%. By using CUDA streams and events, CPU tasks prepare batch N+1 during batch N&#39;s GPU computation, eliminating idle gaps. This method yields more efficient GPU operations without changing kernels or models, enhancing generation speed substantially. <strong><a href="https://thenextweb.com/news/microsoft-startup-deals-life-after-openai?utm_source=tldrai" target="_blank" rel="noreferrer">Microsoft is quietly shopping for an OpenAI replacement (4 minute read)</a></strong> Microsoft signed a deal with OpenAI late April that amended the company&#39;s exclusive license to OpenAI models, freed OpenAI to sell on any other cloud, and removed the AGI clause that would have triggered changes to Microsoft&#39;s IP rights once OpenAI&#39;s board declared the threshold reached. Microsoft&#39;s IP license, a 27% stake worth roughly $135 billion, will be kept through 2032. Microsoft is reportedly looking to purchase Inception, a company that builds diffusion-based language models. It is interesting that Microsoft would spend $13 billion on a partner and then immediately start a shadow procurement process for a replacement. <strong><a href="https://techcrunch.com/2026/05/14/elon-musks-spacexai-has-been-bleeding-staff-since-its-merger/?utm_source=tldrai" target="_blank" rel="noreferrer">Elon Musk&#39;s SpaceXAI has been bleeding staff since its merger (2 minute read)</a></strong> SpaceXAI is reportedly losing top talent across coding, world models, and Grok voice. Rivals like Meta and Thinking Machines Lab are scooping up former staff. Elon Musk&#39;s culture of extreme work has led some staff to leave. Several of the exits could have been driven by a desire to cash out. <strong><a href="https://letsdatascience.com/news/igor-babuschkin-seeks-up-to-1-billion-for-river-ai-8c36ce09?utm_source=tldrai" target="_blank" rel="noreferrer">Igor Babuschkin Seeks Up To $1 Billion For River AI (3 minute read)</a></strong> Babuschkin, an xAI cofounder, is putting in $100 million of his own money into the company. <strong><a href="https://www.cnbc.com/2026/05/13/google-deepmind-alumni-startup-partners-nvidia-superintelligence.html?utm_source=tldrai" target="_blank" rel="noreferrer">Nvidia&#39;s Jensen Huang bets on this British startup to build &#39;next frontier&#39; of AI (3 minute read)</a></strong> Nvidia has announced a partnership with Ineffable Intelligence, a startup pursuing superintelligence that was founded in late 2025 by UCL professor and former lead of DeepMind&#39;s reinforcement learning team, David Silver. <strong><a href="https://openai.com/index/work-with-codex-from-anywhere/?utm_source=tldrai" target="_blank" rel="noreferrer">Work with Codex from anywhere (6 minute read)</a></strong> Codex is now available in the ChatGPT mobile app, enabling seamless remote access to ongoing work on laptops, devboxes, or remote environments. <strong><a href="https://www.testingcatalog.com/opensquilla-launches-open-source-ai-agent-to-cut-token-costs/?utm_source=tldrai" target="_blank" rel="noreferrer">OpenSquilla launches open-source AI agent to cut token costs (4 minute read)</a></strong> OpenSquilla has introduced an open-source AI agent runtime designed to reduce unnecessary token spend by reusing context efficiently. <strong><a href="https://jobs.ashbyhq.com/tldr.tech/3b21aaf8-dea5-4127-be71-602d30e5001e?utm_source=tldrai" target="_blank" rel="noreferrer">TLDR is hiring a Senior Software Engineer, Applied AI ($250k-$350k, Fully Remote)</a></strong> TLDR&#39;s Applied AI team is tasked with making every process at TLDR legible to code, runnable by anyone, and composable into larger workflows. Join a small, fast moving team using the latest AI tools with an unlimited token budget. Learn more . <strong><a href="https://www.datadoghq.com/blog/ai/toto-2/?utm_source=tldrai" target="_blank" rel="noreferrer">Toto 2.0: Time series forecasting enters the scaling era (13 minute read)</a></strong> Datadog&#39;s Toto 2.0, a scalable time series forecasting model family, is now available on Hugging Face.</p><hr>',19)])])}const m=t(o,[["render",i]]);export{g as __pageData,m as default};
